import json
from datetime import date, timedelta



def get_records(day):
    #  create connection object to the postgres db
    conn = psycopg.connect("postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production")

    # create cursor objects on conn object, 
    cur = conn.cursor()
   
    try:

        # sql query to get the number of users who joined in a given day.

        query_string = """
                    SELECT COUNT(DISTINCT user_id) FROM production.users WHERE "date"::DATE <= %s::DATE;
                """
         # execute query on conn object, 
        cur.execute(query_string,[day])
    
        
        results =  dict(cur.fetchone())
        return json.dumps({'count':results['count']})

    except (Exception, psycopg2.Error) as error :
        print ("Error while fetching data from PostgreSQL",error)
    finally:

        # close cursor objects on conn object.
        cur.close()
        conn.close()

def lambda_handler(event, context):
    
    today = date.today().strftime('%Y-%m-%d')

    response = {"today":get_records(today)}
    return json.dumps(response)

